import random

class FallingPiece:
    def __init__(self, tetromino, grid):
        self.tetromino = tetromino
        self.x = grid.width // 2 - 2  # Center at the top
        self.y = 0
        self.grid = grid

    def move(self, dx, dy):
        new_x = self.x + dx
        new_y = self.y + dy
        if self.is_valid_position(new_x, new_y):
            self.x = new_x
            self.y = new_y
            return True
        return False

    def rotate(self, direction):
        original_rotation_index = self.tetromino.rotation_index
        self.tetromino.rotate(direction)
        if not self.is_valid_position(self.x, self.y):
            # Revert rotation if it leads to an invalid position
            self.tetromino.rotation_index = original_rotation_index
            self.tetromino.blocks = list(self.tetromino.rotations[self.tetromino.rotation_index])

    def is_valid_position(self, x, y):
        blocks = self.tetromino.get_blocks(x, y)
        for block_x, block_y in blocks:
            if not self.grid.is_inside(block_x, block_y):
                return False
            if block_y >= 0 and self.grid.get_cell(block_x, block_y).state == CellState.FILLED:
                return False
        return True

    def lock(self):
        blocks = self.tetromino.get_blocks(self.x, self.y)
        for block_x, block_y in blocks:
            self.grid.set_cell(block_x, block_y, CellState.FILLED, self.tetromino.color)

def get_new_tetromino():
    shape_key = random.choice(list(BASE_SHAPES.keys()))
    return Tetromino(shape_key)
